// Serve the main sailing weather app page, injecting server-side config
async function serveApp(c: any) {
  const rawHtml = templates.get('sailing-app');
  if (!rawHtml) return c.text('Template not found', 500);

  // Inject the playback interval config into the template
  const intervalMs = config.get('TIMELINE_PLAY_INTERVAL_MS') || 1500;
  // Inject the default boat speed for the route planner's speed input
  const defaultSpeed = config.get('ROUTE_DEFAULT_SPEED_KNOTS') || 5;

  const html = rawHtml
    .replace('{{PLAY_INTERVAL_MS}}', String(intervalMs))
    .replace('{{ROUTE_DEFAULT_SPEED}}', String(defaultSpeed));

  return c.html(html);
}
